// Calculate product-level per-channel averages
function calcProductChScores(p) {
  const active = p.v.filter(v => !v.disc);
  if (!active.length) return {};
  const sums = {}; const counts = {};
  active.forEach(v => { if (v.chs) Object.entries(v.chs).forEach(([k, s]) => { sums[k] = (sums[k] || 0) + s; counts[k] = (counts[k] || 0) + 1; }); });
  const avg = {};
  Object.keys(sums).forEach(k => { avg[k] = Math.round(sums[k] / counts[k]); });
  return avg;
}

